import json, re, pandas as pd

with open(var_call_zbZVBzAf6L1maBUDhJpN84JT, 'r') as f:
    business_docs = json.load(f)
with open(var_call_HtUP2QtCM4W2py1nVbQumg46, 'r') as f:
    review_rows = json.load(f)

# DataFrames
df_biz = pd.DataFrame(business_docs)
df_rev = pd.DataFrame(review_rows)

# Prepare regex patterns to capture state
patterns = [re.compile(r"in\s+[^,]+,\s*([A-Z]{2})\b"),
            re.compile(r",\s*([A-Z]{2})[,\.]"),
            re.compile(r",\s*([A-Z]{2})\b"),
            re.compile(r"\b([A-Z]{2})\s*$")]

VALID = set(['AL','AK','AZ','AR','CA','CO','CT','DE','FL','GA','HI','ID','IL','IN','IA','KS','KY','LA','ME','MD','MA','MI','MN','MS','MO','MT','NE','NV','NH','NJ','NM','NY','NC','ND','OH','OK','OR','PA','RI','SC','SD','TN','TX','UT','VT','VA','WA','WV','WI','WY','DC'])

def extract_state(desc):
    if not isinstance(desc, str):
        return None
    for p in patterns:
        m = p.search(desc)
        if m:
            # state might be in group 1 or last group
            for g in range(1, len(m.groups())+1):
                code = m.group(g)
                if code and code.upper() in VALID:
                    return code.upper()
    return None

# Apply extraction
if 'description' in df_biz.columns:
    df_biz['state'] = df_biz['description'].apply(extract_state)
else:
    df_biz['state'] = None

# Build mapping
biz_state_map = {row['business_id']: row['state'] for row in df_biz.to_dict(orient='records')}

# Prepare reviews
if 'rating' in df_rev.columns:
    df_rev['rating'] = pd.to_numeric(df_rev['rating'], errors='coerce')
else:
    df_rev['rating'] = None

if 'business_ref' in df_rev.columns:
    df_rev['business_id'] = df_rev['business_ref'].str.replace('businessref_', 'businessid_', regex=False)
else:
    df_rev['business_id'] = None

# Map to state
df_rev['state'] = df_rev['business_id'].map(biz_state_map)

# Filter
df_valid = df_rev[df_rev['state'].notna() & df_rev['rating'].notna()].copy()

# Aggregate per state
if df_valid.empty:
    result = {'state': None, 'review_count': 0, 'average_rating': None, 'notes': 'No reviews mapped to states.'}
else:
    agg = df_valid.groupby('state').agg(review_count=('rating','size'), average_rating=('rating','mean'))
    agg = agg.sort_values('review_count', ascending=False)
    top_state = agg.index[0]
    top_count = int(agg.iloc[0]['review_count'])
    avg_rating = round(float(agg.iloc[0]['average_rating']), 3)
    result = {'state': top_state, 'review_count': top_count, 'average_rating': avg_rating}

# Also include some diagnostics
diag = {
    'total_business_docs': len(df_biz),
    'businesses_with_state_extracted': int(df_biz['state'].notna().sum()),
    'total_reviews': len(df_rev),
    'reviews_mapped_to_state': int(df_valid.shape[0])
}

output = {'result': result, 'diagnostics': diag}
print('__RESULT__:')
print(json.dumps(output))

